{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/duration.py","content":"import re

_DURATION_RE = re.compile(r'([0-9]+(?:\.[0-9]+)?)(ms|s|m|h)')
_MULTIPLIERS = {'ms': 0.001, 's': 1.0, 'm': 60.0, 'h': 3600.0}

def parse_duration(value: str) -> float:
    if not isinstance(value, str): raise ValueError('duration must be a string')
    match = _DURATION_RE.fullmatch(value)
    if match is None: raise ValueError('invalid duration')
    number, unit = match.groups()
    return float(number) * _MULTIPLIERS[unit]
